25	const PROCESSING_FEE = 5;
26	const SWORD_BASE_PREMIUM = 100;
27	const AMULET_BASE_PREMIUM = 60;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	
30	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
31	  const items = input.steps[0].items ?? [];
32	  const basePremium =
33	    items.length === 0
34	      ? 0
35	      : items[0].type === "amulet"
36	        ? AMULET_BASE_PREMIUM
37	        : SWORD_BASE_PREMIUM;
38	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
39	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
40	  return { results: [{ premium }] };
41	};
